export interface TarotCardData {
  name: string;
  meaning: string;
  meaningSummary: string;
  advice: string;
  image: string;
  keywords: string[];
  description: string;
  meaningReversed?: string; 
  meaningReversedSummary?: string;
  adviceReversed?: string;  
  descriptionReversed?: string;
}

export type SpreadType = 'SINGLE' | 'THREE_CARD' | 'CELTIC_CROSS';
export type ThreeCardMode = 'TIME' | 'CAUSE' | 'RELATION';

export interface CardPosition {
  label: string;
  description: string;
  x: number;
  y: number;
  z: number;
  rotation?: [number, number, number];
}

export const SPREAD_CONFIGS: Record<SpreadType, {
  name: string;
  cardCount: number;
  getPositions: (mode?: ThreeCardMode) => CardPosition[];
}> = {
  SINGLE: {
    name: '单张牌阵',
    cardCount: 1,
    getPositions: () => [
      { label: '核心指引', description: '当前的中心能量', x: 0, y: -5.0, z: 12 }
    ]
  },
  THREE_CARD: {
    name: '三张牌阵',
    cardCount: 3,
    getPositions: (mode = 'TIME') => {
      const yBase = -5.2;
      const zBase = 12.5;
      if (mode === 'CAUSE') {
        return [
          { label: '起因', description: '问题的源头', x: -3.5, y: yBase, z: zBase },
          { label: '经过', description: '当前的发展', x: 0, y: yBase, z: zBase },
          { label: '结果', description: '最终的影响', x: 3.5, y: yBase, z: zBase }
        ];
      }
      if (mode === 'RELATION') {
        return [
          { label: '自身', description: '你的态度与状态', x: -3.5, y: yBase, z: zBase },
          { label: '对方', description: '对方的态度与状态', x: 0, y: yBase, z: zBase },
          { label: '关系', description: '关系的现状', x: 3.5, y: yBase, z: zBase }
        ];
      }
      return [
        { label: '过去', description: '已发生的影响', x: -3.5, y: yBase, z: zBase },
        { label: '现在', description: '当前的能量', x: 0, y: yBase, z: zBase },
        { label: '未来', description: '潜在的趋势', x: 3.5, y: yBase, z: zBase }
      ];
    }
  },
  CELTIC_CROSS: {
    name: '凯尔特十字',
    cardCount: 10,
    getPositions: () => {
      const yBase = -5.0;
      const zBase = 13;
      const step = 1.8;
      return [
        ...Array.from({ length: 10 }).map((_, i) => ({
            label: `${i+1}`,
            description: '待解析',
            x: (i - 4.5) * step,
            y: yBase,
            z: zBase,
            rotation: [0.3, 0, 0] as [number, number, number]
        }))
      ];
    }
  }
};

